/* Fix: On screens narrower than 600px, the sidebar
   should stack below the content instead of beside it */
.page {
  display: flex;
  gap: 16px;
}
.content {
  flex: 1;
  padding: 16px;
  background-color: #f5f5f5;
}
.sidebar {
  width: 200px;
  padding: 16px;
  background-color: #e0e0e0;
}
/* The media query below is broken - fix it */
@media (max-width: 600px) {
  .page {
    flex-direction: row; /* should stack */
  }
  .sidebar {
    width: 200px; /* should be full width */
  }
}

referenceSolutions:
.page {
  display: flex;
  gap: 16px;
}
.content {
  flex: 1;
  padding: 16px;
  background-color: #f5f5f5;
}
.sidebar {
  width: 200px;
  padding: 16px;
  background-color: #e0e0e0;
}
@media (max-width: 600px) {
  .page {
    flex-direction: column;
  }
  .sidebar {
    width: 100%;
  }
}

.page {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}
.content {
  flex: 1;
  min-width: 300px;
  padding: 16px;
  background-color: #f5f5f5;
}
.sidebar {
  width: 200px;
  padding: 16px;
  background-color: #e0e0e0;
}
@media (max-width: 600px) {
  .page {
    flex-direction: column;
  }
  .sidebar {
    width: auto;
  }
}
